@page "/shipments"
@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Shipments — Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>

<div class="row mb-3 g-2 align-items-end">
    <div class="col-md-4">
        <label class="form-label">Filter by status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@FormatStatus(s)</option>
            }
        </select>
    </div>
    <div class="col-md-4">
        <label class="form-label">Search destination</label>
        <input class="form-control" placeholder="e.g. London" @bind="destinationSearch" @bind:event="oninput" />
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match your filters.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Recipient</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.RecipientName</td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @StatusBadgeClass(shipment.Status)">@FormatStatus(shipment.Status)</span></td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (shipment.Status != ShipmentStatus.Delivered)
                            {
                                <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                        @onchange="e => UpdateStatus(shipment, e)">
                                    <option value="" disabled selected>Update…</option>
                                    @foreach (var s in Enum.GetValues<ShipmentStatus>().Where(s => s != shipment.Status))
                                    {
                                        <option value="@((int)s)">@FormatStatus(s)</option>
                                    }
                                </select>
                            }
                            else
                            {
                                <span class="text-success">✓ Complete</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string destinationSearch = "";

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter)
            .Where(s => string.IsNullOrEmpty(destinationSearch) ||
                        s.Destination.Contains(destinationSearch, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && int.TryParse(val, out var statusInt))
        {
            var newStatus = (ShipmentStatus)statusInt;
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            var index = shipments!.FindIndex(s => s.Id == shipment.Id);
            if (index >= 0)
                shipments[index] = updated;
        }
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Delayed => "Delayed",
        _ => status.ToString()
    };

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g. TRK-1001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Search
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedNumber</strong>. Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@shipment.TrackingNumber</strong>
            <span class="badge @StatusBadgeClass(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h6 class="text-muted">Route</h6>
                    <p class="mb-1"><strong>From:</strong> @shipment.Origin</p>
                    <p><strong>To:</strong> @shipment.Destination</p>
                </div>
                <div class="col-md-6">
                    <h6 class="text-muted">Delivery Details</h6>
                    <p class="mb-1"><strong>Recipient:</strong> @shipment.RecipientName</p>
                    <p class="mb-1"><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("dddd, MMM dd, yyyy")</p>
                    <p><strong>Shipped On:</strong> @shipment.CreatedAt.ToString("MMM dd, yyyy")</p>
                </div>
            </div>

            <hr />

            <h6 class="text-muted">Shipment Progress</h6>
            <div class="progress" style="height: 25px;">
                <div class="progress-bar @ProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @ProgressPercent(shipment.Status)%"
                     aria-valuenow="@ProgressPercent(shipment.Status)"
                     aria-valuemin="0"
                     aria-valuemax="100">
                    @FormatStatus(shipment.Status)
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool searched;
    private bool searching;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        searching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Delayed => "Delayed",
        _ => status.ToString()
    };

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string ProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int ProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}

